protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // EF Core 9 changed the default discriminator property from "Discriminator" to "$type".
        // Existing 500K documents use "Discriminator" — preserve it for data compatibility
        // and so direct SQL queries (c.Discriminator) keep working.
        entity.HasDiscriminator<string>("Discriminator");

        // EF Core 9 changed id format from "Product|123" to "123".
        // Existing documents use the compound format — preserve it so point-reads
        // and FindAsync continue to locate existing data.
        entity.HasRootDiscriminatorInJsonId(true);
    });

    // Removed: HasIndex() — EF Core 9 Cosmos provider throws at startup.
    // Manage indexing via the Azure Portal / Bicep / Terraform indexing policy instead.
}

